-- [ops-fault-support staff] tb_staff 직원 디렉터리 시드 (정도유아이티 조직도 41이미지 전사, 멱등).
-- 겸직자는 표기 조직마다 1행. 직급/소속 수정은 조직도 관리 화면(직원 추가/수정/삭제).


-- SW지원팀 직급 보정 (기존 시드 정정)
UPDATE tb_staff SET position='이사' WHERE name='박욱진' AND org_unit_id=(SELECT unit_id FROM tb_org_unit WHERE name='SW지원팀' AND unit_type='TEAM');
UPDATE tb_staff SET position='부장' WHERE name='김한준' AND org_unit_id=(SELECT unit_id FROM tb_org_unit WHERE name='SW지원팀' AND unit_type='TEAM');
UPDATE tb_staff SET position='과장' WHERE name='서현규' AND org_unit_id=(SELECT unit_id FROM tb_org_unit WHERE name='SW지원팀' AND unit_type='TEAM');
